    tags = [w.lower() for w in words if w.lower() not in skip and len(w) > 1]
    return ", ".join(tags) if tags else tool_name


def _build_method_signature(method_name: str, params: list[dict]) -> str:
    parts = ["self"]
    for p in params:
        if p["required"]:
