    skill_name: str,
    description: str,
    tools: list,
    class_name: str = "App",
    auth_type: str = "none",
    auth_header: str | None = None,
) -> str:
    if len(description) > 1024:
        description = description[:1021] + "..."

    tool_docs = _prepare_tool_docs(tools)

    template = _env.get_template("skill.md.j2")
    content = template.render(
